#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include "../common.h"

void kernel_cpu(int cores_arg,
                record *records,
                knode *knodes,
                long knodes_elem,
                int order,
                long maxheight,
                int count,
                long *currKnode,
                long *offset,
                int *keys,
                record *ans)
{
    int total_threads = count * order;

    #pragma omp parallel num_threads(total_threads)
    {
        int global_id = omp_get_thread_num();
        int bid = global_id / order;
        int thid = global_id % order;

        if(bid < count) {
            for(int i = 0; i < maxheight; i++) {
                if(thid < knodes[currKnode[bid]].num_keys - 1) {
                    if(knodes[currKnode[bid]].keys[thid] <= keys[bid] && 
                       knodes[currKnode[bid]].keys[thid+1] > keys[bid]) {
                        if(knodes[offset[bid]].indices[thid] < knodes_elem) {
                            offset[bid] = knodes[offset[bid]].indices[thid];
                        }
                    }
                }

                #pragma omp barrier

                if(thid == 0) {
                    currKnode[bid] = offset[bid];
                }

                #pragma omp barrier
            }

            if(thid < knodes[currKnode[bid]].num_keys) {
                if(knodes[currKnode[bid]].keys[thid] == keys[bid]) {
                    ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
                }
            }
        }
    }
}

