int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
    int in, hid, out;
    float out_err, hid_err;

    in = net->input_n;
    hid = net->hidden_n;
    out = net->output_n;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

