    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
    float *partial_sum;
    float sum;
    int num_blocks = in / BLOCK_SIZE;

