    #pragma omp parallel for shared(input_weights_one_dim, net->input_units, partial_sum) private(sum, m, k, j) reduction(+:sum)
    for (int j = 1; j <= hid; j++) {
        sum = 0.0;
        for (int k = 0; k <= in; k++) {
            sum += input_weights_one_dim[k * (hid + 1) + j] * net->input_units[k];
        }
        net->hidden_units[j] = squash(sum);
    }

    for (int j = 1; j <= hid; j++) {
        sum = 0.0;
        for (int k = 0; k < num_blocks; k++) {
            sum += partial_sum[k * hid + j - 1];
