float squash(float x)
{
    return (1.0 / (1.0 + exp(-x)));
}

float *alloc_1d_dbl(int n)
{
    float *new_t;
    new_t = (float *) malloc((unsigned) (n * sizeof(float)));
    if (new_t == NULL) {
