#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

	int m = 0;
	for (int k = 0; k <= in; k++) {
		for (int j = 0; j <= hid; j++) {
		input_weights_one_dim[m] = net->input_weights[k][j];
		input_weights_prev_one_dim[m] = net-> input_prev_weights[k][j];
	    m++;
		}
	}

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	printf("Performing CPU computation\n");

	// OpenMP parallel version of bpnn_layerforward_ocl
	#pragma omp parallel for num_threads(num_threads) shared(input_weights_one_dim, net, partial_sum, in, hid, num_blocks) private(m, sum)
	for (int by = 0; by < num_blocks; by++) {
		for (int ty = 0; ty < HEIGHT; ty++) {
			float local_weight[WIDTH];
			float input_node = net->input_units[HEIGHT * by + ty + 1];

			for (int tx = 0; tx < WIDTH; tx++) {
				int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
				local_weight[tx] = input_weights_one_dim[index] * input_node;
			}

			for (int i = 1; i <= HEIGHT; i = i * 2) {
				int power_two = i;
				if (ty % power_two == 0) {
					for (int tx = 0; tx < WIDTH; tx++) {
						if (ty + power_two/2 < HEIGHT) {
							int idx2 = (hid + 1) * HEIGHT * by + (hid + 1) * (ty + power_two/2) + tx + 1 + (hid + 1);
							local_weight[tx] += input_weights_one_dim[idx2];
						}
					}
				}
			}

			for (int tx = 0; tx < WIDTH; tx++) {
				int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
				input_weights_one_dim[index] = local_weight[tx];

				if (tx == 0) {
					partial_sum[by * hid + ty] = local_weight[tx];
				}
			}
		}
	}

	for (int j = 1; j <= hid; j++) {
		sum = 0.0;
		for (int k = 0; k < num_blocks; k++) {
			sum += partial_sum[k * hid + j-1];
		}
		sum += net->input_weights[0][j];
		net->hidden_units[j] = 1.0 / (1.0 + exp(-sum));
	}

	bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
	bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
	bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
	bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

	// OpenMP parallel version of bpnn_adjust_weights_ocl
	#pragma omp parallel for num_threads(num_threads) shared(input_weights_one_dim, input_weights_prev_one_dim, net) private(m)
	for (int by = 0; by < num_blocks; by++) {
		for (int ty = 0; ty < HEIGHT; ty++) {
			for (int tx = 0; tx < WIDTH; tx++) {
				int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
				int index_y = HEIGHT * by + ty + 1;
				int index_x = tx + 1;

				float delta_val = net->hidden_delta[index_x];
				float ly_val = net->input_units[index_y];
				float oldw_val = input_weights_prev_one_dim[index];

				float new_dw = ((ETA * delta_val * ly_val) + (MOMENTUM * oldw_val));
				input_weights_one_dim[index] += new_dw;
				input_weights_prev_one_dim[index] = new_dw;

				if (ty == 0 && by == 0) {
					net->input_units[index_x] += ((ETA * delta_val) + (MOMENTUM * oldw_val));
				}
			}
		}
	}

	// Copy back from 1D array to 2D array
	m = 0;
	for (int k = 0; k <= in; k++) {
		for (int j = 0; j <= hid; j++) {
			net->input_weights[k][j] = input_weights_one_dim[m];
			net->input_prev_weights[k][j] = input_weights_prev_one_dim[m];
			m++;
		}
	}

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	free(input_weights_prev_one_dim);
	free(partial_sum);
	free(input_weights_one_dim);
	free(source);

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	tvsub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif

	return 0;
}

