		old_variables = new float[nelr*NVAR];   	
		fluxes = new float[nelr*NVAR];
		step_factors = new float[nelr]; 

		initialize_variables(old_variables, ff_variable, nelr);	
		initialize_variables(fluxes, ff_variable, nelr);		
		for(int i = 0; i < nelr; i++) step_factors[i] = 0.0f;

		std::cout << "Starting..." << std::endl;

		for(int i = 0; i < iterations; i++){
			for(int k = 0; k < nelr*NVAR; k++) old_variables[k] = variables[k];

			compute_step_factor(variables, areas, step_factors, nelr);
			for(int j = 0; j < RK; j++){
				compute_flux(elements_surrounding_elements, normals, variables, ff_variable, fluxes, ff_flux_contribution_density_energy, \
				ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z, nelr);

				time_step(j, nelr, old_variables, variables, step_factors, fluxes);
			}
