		std::cout << "Saving solution..." << std::endl;
		dump(variables, nel, nelr);
		std::cout << "Saved solution..." << std::endl;
		std::cout << "Cleaning up..." << std::endl;

		delete[] ff_variable;
		delete[] ff_flux_contribution_momentum_x;
		delete[] ff_flux_contribution_momentum_y;
		delete[] ff_flux_contribution_momentum_z;
		delete[] ff_flux_contribution_density_energy;
		delete[] areas;
		delete[] elements_surrounding_elements;
		delete[] normals;
		delete[] variables;
		delete[] old_variables;
		delete[] fluxes;
		delete[] step_factors;
		std::cout << "Done..." << std::endl;
	}
	catch(std::string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;		
		delete[] ff_variable;
		delete[] ff_flux_contribution_momentum_x;
		delete[] ff_flux_contribution_momentum_y;
		delete[] ff_flux_contribution_momentum_z;
		delete[] ff_flux_contribution_density_energy;
