            variance = (in_sqr_final_sum[0] / d_common.in_elem) - mean_sqr;
            deviation = sqrt(variance);
            denomT[0] = sqrt((fp)(d_common.in_elem - 1)) * deviation;

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                checksum[28] = checksum[28] + denomT[0];
            }
#endif

            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * denomT[0];
            }

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                for(i = 0; i < d_common.in2_sub2_elem; i++) {
                    checksum[29] = checksum[29] + d_unique_d_in2_sqr_sub2[i];
                }
            }
#endif

            for(ei_new = 0; ei_new < d_common.conv_elem; ei_new++) {
                d_unique_d_conv[ei_new] = d_unique_d_conv[ei_new] - d_unique_d_in2_sub2[ei_new] * in_final_sum[0] / d_common.in_elem;
            }

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                for(i = 0; i < d_common.conv_elem; i++) {
                    checksum[30] = checksum[30] + d_unique_d_conv[i];
                }
            }
#endif

            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_conv[ei_new] / d_unique_d_in2_sqr_sub2[ei_new];
            }

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                for(i = 0; i < d_common.in2_sub2_elem; i++) {
                    checksum[31] = checksum[31] + d_unique_d_in2_sqr_sub2[i];
                }
            }
#endif

            cent = d_common.sSize + d_common.tSize + 1;
            if(d_frame_no == 0) {
                tMask_row = cent + d_unique_d_Row[d_unique_point_no] - d_unique_d_Row[d_unique_point_no] - 1;
                tMask_col = cent + d_unique_d_Col[d_unique_point_no] - d_unique_d_Col[d_unique_point_no] - 1;
            } else {
                pointer = d_unique_point_no * d_common.no_frames + d_frame_no - 1;
                tMask_row = cent + d_unique_d_tRowLoc[pointer] - d_unique_d_Row[d_unique_point_no] - 1;
                tMask_col = cent + d_unique_d_tColLoc[pointer] - d_unique_d_Col[d_unique_point_no] - 1;
            }

            for(ei_new = 0; ei_new < d_common.tMask_elem; ei_new++) {
                location = tMask_col * d_common.tMask_rows + tMask_row;
                if(ei_new == location) {
                    d_unique_d_tMask[ei_new] = 1;
                } else {
                    d_unique_d_tMask[ei_new] = 0;
                }
            }

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                for(i = 0; i < d_common.tMask_elem; i++) {
                    checksum[32] = checksum[32] + d_unique_d_tMask[i];
                }
            }
#endif

            for(ei_new = 0; ei_new < d_common.mask_conv_elem; ei_new++) {
                ic = (ei_new + 1) % d_common.mask_conv_rows;
                jc = (ei_new + 1) / d_common.mask_conv_rows + 1;
                if((ei_new + 1) % d_common.mask_conv_rows == 0) {
                    ic = d_common.mask_conv_rows;
                    jc = jc - 1;
                }
                j = jc + d_common.mask_conv_joffset;
                jp1 = j + 1;
                if(d_common.mask_cols < jp1) ja1 = jp1 - d_common.mask_cols;
                else ja1 = 1;
                if(d_common.tMask_cols < j) ja2 = d_common.tMask_cols;
                else ja2 = j;
                i = ic + d_common.mask_conv_ioffset;
                ip1 = i + 1;
                if(d_common.mask_rows < ip1) ia1 = ip1 - d_common.mask_rows;
                else ia1 = 1;
                if(d_common.tMask_rows < i) ia2 = d_common.tMask_rows;
                else ia2 = i;
                s = 0;
                for(ja = ja1; ja <= ja2; ja++) {
                    jb = jp1 - ja;
                    for(ia = ia1; ia <= ia2; ia++) {
                        ib = ip1 - ia;
                        s = s + d_unique_d_tMask[d_common.tMask_rows * (ja - 1) + ia - 1] * 1;
                    }
                }
                d_unique_d_mask_conv[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * s;
            }

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                for(i = 0; i < d_common.mask_conv_elem; i++) {
                    checksum[33] = checksum[33] + d_unique_d_mask_conv[i];
                }
            }
#endif

            for(ei_new = 0; ei_new < d_common.mask_conv_rows; ei_new++) {
                largest_value = 0;
                largest_coordinate = 0;
                for(i = 0; i < d_common.mask_conv_cols; i++) {
                    largest_coordinate_current = ei_new * d_common.mask_conv_cols + i;
                    largest_value_current = fabs(d_unique_d_mask_conv[largest_coordinate_current]);
                    if(largest_value_current > largest_value) {
                        largest_coordinate = largest_coordinate_current;
                        largest_value = largest_value_current;
                    }
                }
                par_max_coo[ei_new] = largest_coordinate;
                par_max_val[ei_new] = largest_value;
            }

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                for(i = 0; i < d_common.mask_conv_rows; i++) {
                    checksum[34] = checksum[34] + par_max_coo[i] + par_max_val[i];
                }
            }
#endif

            fin_max_val = 0;
            fin_max_coo = 0;
            for(i = 0; i < d_common.mask_conv_rows; i++) {
                if(par_max_val[i] > fin_max_val) {
                    fin_max_val = par_max_val[i];
                    fin_max_coo = par_max_coo[i];
                }
            }

            largest_row = (fin_max_coo + 1) % d_common.mask_conv_rows - 1;
            largest_col = (fin_max_coo + 1) / d_common.mask_conv_rows;
            if((fin_max_coo + 1) % d_common.mask_conv_rows == 0) {
                largest_row = d_common.mask_conv_rows - 1;
                largest_col = largest_col - 1;
            }
            largest_row = largest_row + 1;
            largest_col = largest_col + 1;
            offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
            offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
            pointer = d_unique_point_no * d_common.no_frames + d_frame_no;
            d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no] + offset_row;
            d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no] + offset_col;

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                checksum[35] = checksum[35] + d_unique_d_tRowLoc[pointer] + d_unique_d_tColLoc[pointer];
            }
#endif
        }

        if(d_frame_no != 0 && (d_frame_no) % 10 == 0) {
#ifdef INIT
            for(i = 0; i < d_common.in_elem; i++) {
                d_in[i] = 0;
            }
#endif

            loc_pointer = d_unique_point_no * d_common.no_frames + d_frame_no;
            d_unique_d_Row[d_unique_point_no] = d_unique_d_tRowLoc[loc_pointer];
            d_unique_d_Col[d_unique_point_no] = d_unique_d_tColLoc[loc_pointer];

            for(ei_new = 0; ei_new < d_common.in_elem; ei_new++) {
                row = (ei_new + 1) % d_common.in_rows - 1;
                col = (ei_new + 1) / d_common.in_rows + 1 - 1;
                if((ei_new + 1) % d_common.in_rows == 0) {
                    row = d_common.in_rows - 1;
                    col = col - 1;
                }
                ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
                ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
                ori_pointer = ori_col * d_common.frame_rows + ori_row;
                d_in[ei_new] = d_common.alpha * d_in[ei_new] + (1 - d_common.alpha) * d_common_change_d_frame[ori_pointer];
            }

#ifdef TEST_CHECKSUM
            if(bx == 0) {
                for(i = 0; i < d_common.in_elem; i++) {
                    checksum[36] = checksum[36] + d_in[i];
                }
            }
#endif
        }
    }
}

void kernel_gpu_opencl_wrapper(
    params_common common,
    int* endoRow,
    int* endoCol,
    int* tEndoRowLoc,
    int* tEndoColLoc,
    int* epiRow,
    int* epiCol,
    int* tEpiRowLoc,
    int* tEpiColLoc,
    avi_t* frames)
{
    int i, frame_no;
    fp* frame;
    fp* checksum;

    fp* d_frame = (fp*)malloc(common.frame_mem);
    fp* d_endoT = (fp*)malloc(common.in_mem * common.endoPoints);
    fp* d_epiT = (fp*)malloc(common.in_mem * common.epiPoints);
    fp* d_in2_all = (fp*)malloc(common.in2_mem * common.allPoints);
    fp* d_conv_all = (fp*)malloc(common.conv_mem * common.allPoints);
    fp* d_in2_pad_cumv_all = (fp*)malloc(common.in2_pad_cumv_mem * common.allPoints);
    fp* d_in2_pad_cumv_sel_all = (fp*)malloc(common.in2_pad_cumv_sel_mem * common.allPoints);
    fp* d_in2_sub_cumh_all = (fp*)malloc(common.in2_sub_cumh_mem * common.allPoints);
    fp* d_in2_sub_cumh_sel_all = (fp*)malloc(common.in2_sub_cumh_sel_mem * common.allPoints);
    fp* d_in2_sub2_all = (fp*)malloc(common.in2_sub2_mem * common.allPoints);
    fp* d_in2_sqr_all = (fp*)malloc(common.in2_sqr_mem * common.allPoints);
    fp* d_in2_sqr_sub2_all = (fp*)malloc(common.in2_sqr_sub2_mem * common.allPoints);
    fp* d_in_sqr_all = (fp*)malloc(common.in_sqr_mem * common.allPoints);
    fp* d_tMask_all = (fp*)malloc(common.tMask_mem * common.allPoints);
    fp* d_mask_conv_all = (fp*)malloc(common.mask_conv_mem * common.allPoints);
    fp* d_in_mod_temp_all = (fp*)malloc(sizeof(fp) * common.in_elem * common.allPoints);
    fp* in_partial_sum_all = (fp*)malloc(sizeof(fp) * common.in_cols * common.allPoints);
    fp* in_sqr_partial_sum_all = (fp*)malloc(sizeof(fp) * common.in_sqr_rows * common.allPoints);
    fp* par_max_val_all = (fp*)malloc(sizeof(fp) * common.mask_conv_rows * common.allPoints);
    int* par_max_coo_all = (int*)malloc(sizeof(int) * common.mask_conv_rows * common.allPoints);
    fp* in_final_sum_all = (fp*)malloc(sizeof(fp) * common.allPoints);
    fp* in_sqr_final_sum_all = (fp*)malloc(sizeof(fp) * common.allPoints);
    fp* denomT_all = (fp*)malloc(sizeof(fp) * common.allPoints);
    fp* checksum_all = (fp*)malloc(sizeof(fp) * CHECK);

    printf("frame progress: ");
    fflush(stdout);

    for(frame_no = 0; frame_no < common.frames_processed; frame_no++) {
        frame = get_frame(frames, frame_no, 0, 0, 1);

        for(i = 0; i < common.frame_elem; i++) {
            d_frame[i] = frame[i];
        }
        free(frame);

        kernel_gpu_opencl(
            common,
            d_frame,
            frame_no,
            endoRow,
            endoCol,
            tEndoRowLoc,
            tEndoColLoc,
            epiRow,
            epiCol,
            tEpiRowLoc,
            tEpiColLoc,
            d_endoT,
            d_epiT,
            d_in2_all,
            d_conv_all,
            d_in2_pad_cumv_all,
            d_in2_pad_cumv_sel_all,
            d_in2_sub_cumh_all,
            d_in2_sub_cumh_sel_all,
            d_in2_sub2_all,
            d_in2_sqr_all,
            d_in2_sqr_sub2_all,
            d_in_sqr_all,
            d_tMask_all,
            d_mask_conv_all,
            d_in_mod_temp_all,
            in_partial_sum_all,
            in_sqr_partial_sum_all,
            par_max_val_all,
            par_max_coo_all,
            in_final_sum_all,
            in_sqr_final_sum_all,
            denomT_all,
            checksum_all);

#ifdef TEST_CHECKSUM
        checksum = (fp*)malloc(sizeof(fp) * CHECK);
        for(i = 0; i < CHECK; i++) {
            checksum[i] = checksum_all[i];
        }
        printf("CHECKSUM:\n");
        for(i = 0; i < CHECK; i++) {
            printf("%f ", checksum[i]);
        }
        printf("\n\n");
        free(checksum);
#endif

        printf("%d ", frame_no);
        fflush(stdout);
    }

    printf("\n");
    fflush(stdout);

    free(d_frame);
    free(d_endoT);
    free(d_epiT);
    free(d_in2_all);
    free(d_conv_all);
    free(d_in2_pad_cumv_all);
    free(d_in2_pad_cumv_sel_all);
    free(d_in2_sub_cumh_all);
    free(d_in2_sub_cumh_sel_all);
    free(d_in2_sub2_all);
    free(d_in2_sqr_all);
    free(d_in2_sqr_sub2_all);
    free(d_in_sqr_all);
    free(d_tMask_all);
    free(d_mask_conv_all);
    free(d_in_mod_temp_all);
    free(in_partial_sum_all);
    free(in_sqr_partial_sum_all);
    free(par_max_val_all);
    free(par_max_coo_all);
    free(in_final_sum_all);
    free(in_sqr_final_sum_all);
    free(denomT_all);
    free(checksum_all);
}

#include <omp.h>
#include <math.h>
#include <stdlib.h>
#include <stdio.h>

#include "./main.h"

void kernel_gpu_openmp(
    params_common d_common,
    fp* d_frame,
    int d_frame_no,

    int* d_endoRow,
    int* d_endoCol,
    int* d_tEndoRowLoc,
    int* d_tEndoColLoc,
    int* d_epiRow,
    int* d_epiCol,
    int* d_tEpiRowLoc,
    int* d_tEpiColLoc,

    fp* d_endoT,
    fp* d_epiT,
    fp* d_in2_all,
    fp* d_conv_all,
    fp* d_in2_pad_cumv_all,
    fp* d_in2_pad_cumv_sel_all,
    fp* d_in2_sub_cumh_all,
    fp* d_in2_sub_cumh_sel_all,
    fp* d_in2_sub2_all,
    fp* d_in2_sqr_all,
    fp* d_in2_sqr_sub2_all,
    fp* d_in_sqr_all,
    fp* d_tMask_all,
    fp* d_mask_conv_all,

    fp* d_in_mod_temp_all,
    fp* in_partial_sum_all,
    fp* in_sqr_partial_sum_all,
    fp* par_max_val_all,
    int* par_max_coo_all,

    fp* in_final_sum_all,
    fp* in_sqr_final_sum_all,
    fp* denomT_all,

    fp* checksum)
{
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    fp s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    fp sum;
    int pos_ori;
    fp temp;
    fp temp2;
    int location;
    int cent;
    int tMask_row;
    int tMask_col;
    fp largest_value_current = 0;
    fp largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    fp fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;
    fp mean;
    fp mean_sqr;
    fp variance;
    fp deviation;
    int pointer;
    int ori_pointer;
    int loc_pointer;

    fp* d_common_change_d_frame = &d_frame[0];

#ifdef TEST_CHECKSUM
    if(d_frame_no == 0){
        for(i=0; i<CHECK; i++){
            checksum[i] = 0;
        }
    }
#endif

    #pragma omp parallel for schedule(static)
    for(int bx = 0; bx < d_common.allPoints; bx++){
        int tx = 0;
        int ei_new;

        int d_unique_point_no;
        int* d_unique_d_Row;
        int* d_unique_d_Col;
        int* d_unique_d_tRowLoc;
        int* d_unique_d_tColLoc;
        fp* d_in;

        fp* d_unique_d_in2;
        fp* d_unique_d_conv;
        fp* d_unique_d_in2_pad_cumv;
        fp* d_unique_d_in2_pad_cumv_sel;
        fp* d_unique_d_in2_sub_cumh;
        fp* d_unique_d_in2_sub_cumh_sel;
        fp* d_unique_d_in2_sub2;
        fp* d_unique_d_in2_sqr;
        fp* d_unique_d_in2_sqr_sub2;
        fp* d_unique_d_in_sqr;
        fp* d_unique_d_tMask;
        fp* d_unique_d_mask_conv;

        fp* d_in_mod_temp;
        fp* in_partial_sum;
        fp* in_sqr_partial_sum;
        fp* par_max_val;
        int* par_max_coo;

        fp* in_final_sum;
        fp* in_sqr_final_sum;
        fp* denomT;

        if(bx < d_common.endoPoints){
            d_unique_point_no = bx;
            d_unique_d_Row = d_endoRow;
            d_unique_d_Col = d_endoCol;
            d_unique_d_tRowLoc = d_tEndoRowLoc;
            d_unique_d_tColLoc = d_tEndoColLoc;
            d_in = &d_endoT[d_unique_point_no * d_common.in_elem];
        }
        else{
            d_unique_point_no = bx - d_common.endoPoints;
            d_unique_d_Row = d_epiRow;
            d_unique_d_Col = d_epiCol;
            d_unique_d_tRowLoc = d_tEpiRowLoc;
            d_unique_d_tColLoc = d_tEpiColLoc;
            d_in = &d_epiT[d_unique_point_no * d_common.in_elem];
        }

        d_unique_d_in2 = &d_in2_all[bx*d_common.in2_elem];
        d_unique_d_conv = &d_conv_all[bx*d_common.conv_elem];
        d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx*d_common.in2_pad_cumv_elem];
        d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx*d_common.in2_pad_cumv_sel_elem];
        d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx*d_common.in2_sub_cumh_elem];
        d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx*d_common.in2_sub_cumh_sel_elem];
        d_unique_d_in2_sub2 = &d_in2_sub2_all[bx*d_common.in2_sub2_elem];
        d_unique_d_in2_sqr = &d_in2_sqr_all[bx*d_common.in2_sqr_elem];
        d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx*d_common.in2_sqr_sub2_elem];
        d_unique_d_in_sqr = &d_in_sqr_all[bx*d_common.in_sqr_elem];
        d_unique_d_tMask = &d_tMask_all[bx*d_common.tMask_elem];
        d_unique_d_mask_conv = &d_mask_conv_all[bx*d_common.mask_conv_elem];

        d_in_mod_temp = &d_in_mod_temp_all[bx*d_common.in_elem];
        in_partial_sum = &in_partial_sum_all[bx*d_common.in_cols];
        in_sqr_partial_sum = &in_sqr_partial_sum_all[bx*d_common.in_sqr_rows];
        par_max_val = &par_max_val_all[bx*d_common.mask_conv_rows];
        par_max_coo = &par_max_coo_all[bx*d_common.mask_conv_rows];

        in_final_sum = &in_final_sum_all[bx];
        in_sqr_final_sum = &in_sqr_final_sum_all[bx];
        denomT = &denomT_all[bx];

        if(d_frame_no == 0){
#ifdef INIT
            for(i=0; i<d_common.no_frames; i++){
                d_unique_d_tRowLoc[d_unique_point_no*d_common.no_frames+i] = 0;
                d_unique_d_tColLoc[d_unique_point_no*d_common.no_frames+i] = 0;
            }

            for(i=0; i<d_common.in_elem; i++){
                d_in[i] = 0;
            }
#endif

            ei_new = tx;
            if(ei_new == 0){
                pointer = d_unique_point_no*d_common.no_frames+d_frame_no;
                d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
                d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];
            }

            ei_new = tx;
            while(ei_new < d_common.in_elem){
                row = (ei_new+1) % d_common.in_rows - 1;
                col = (ei_new+1) / d_common.in_rows + 1 - 1;
                if((ei_new+1) % d_common.in_rows == 0){
                    row = d_common.in_rows - 1;
                    col = col-1;
                }

                ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
                ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
                ori_pointer = ori_col*d_common.frame_rows+ori_row;

                d_in[col*d_common.in_rows+row] = d_common_change_d_frame[ori_pointer];

                ei_new = ei_new + NUMBER_THREADS;
            }

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(i=0; i<d_common.in_elem; i++){
                    checksum[0] = checksum[0]+d_in[i];
                }
            }
#endif
        }

        if(d_frame_no != 0){
#ifdef INIT
            for(i=0; i<d_common.in2_elem; i++){
                d_unique_d_in2[i] = 0;
            }
            for(i=0; i<d_common.conv_elem; i++){
                d_unique_d_conv[i] = 0;
            }
            for(i=0; i<d_common.in2_pad_cumv_elem; i++){
                d_unique_d_in2_pad_cumv[i] = 0;
            }
            for(i=0; i<d_common.in2_pad_cumv_sel_elem; i++){
                d_unique_d_in2_pad_cumv_sel[i] = 0;
            }
            for(i=0; i<d_common.in2_sub_cumh_elem; i++){
                d_unique_d_in2_sub_cumh[i] = 0;
