#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

#define BLOCK_SIZE 256
#define BLOCK_SIZE2 256

int *membership_OCL;

int allocate(int n_points, int n_features, int n_clusters, float **feature)
{
    membership_OCL = (int*) malloc(n_points * sizeof(int));
    if (!membership_OCL) {
        printf("ERROR: malloc membership_OCL failed\n");
        return -1;
    }

    return 0;
}

void deallocateMemory()
{
    if (membership_OCL) free(membership_OCL);
    membership_OCL = NULL;
}

void kmeans_kernel_omp(float *feature,
                       float *clusters,
                       int *membership,
                       int npoints,
                       int nclusters,
                       int nfeatures)
{
    #pragma omp parallel for schedule(static)
    for (int point_id = 0; point_id < npoints; point_id++) {
        float min_dist = FLT_MAX;
        int index = 0;

        for (int i = 0; i < nclusters; i++) {
            float dist = 0;
            for (int l = 0; l < nfeatures; l++) {
                float diff = feature[l * npoints + point_id] - clusters[i * nfeatures + l];
                dist += diff * diff;
            }

            if (dist < min_dist) {
                min_dist = dist;
                index = i;
            }
        }

        membership[point_id] = index;
    }
}

void kmeans_swap_omp(float *feature,
                     float *feature_swap,
                     int npoints,
                     int nfeatures)
{
    #pragma omp parallel for schedule(static)
    for (int tid = 0; tid < npoints; tid++) {
        for (int i = 0; i < nfeatures; i++) {
            feature_swap[i * npoints + tid] = feature[tid * nfeatures + i];
        }
    }
}

int kmeansOCL(float **feature,
              int n_features,
              int n_points,
              int n_clusters,
              int *membership,
              float **clusters,
              int *new_centers_len,
              float **new_centers)
{
    int delta = 0;
    int i, j;

    float *feature_swap = (float*) malloc(n_points * n_features * sizeof(float));
    if (!feature_swap) {
        printf("ERROR: malloc feature_swap failed\n");
        return -1;
    }

    kmeans_swap_omp(feature[0], feature_swap, n_points, n_features);

    float *cluster_linear = (float*) malloc(n_clusters * n_features * sizeof(float));
    if (!cluster_linear) {
        printf("ERROR: malloc cluster_linear failed\n");
        free(feature_swap);
        return -1;
    }

    for (i = 0; i < n_clusters; i++) {
        for (j = 0; j < n_features; j++) {
            cluster_linear[i * n_features + j] = clusters[i][j];
        }
    }

    kmeans_kernel_omp(feature_swap, cluster_linear, membership_OCL, n_points, n_clusters, n_features);

    delta = 0;
    for (i = 0; i < n_points; i++) {
        int cluster_id = membership_OCL[i];
        new_centers_len[cluster_id]++;
        if (membership_OCL[i] != membership[i]) {
            delta++;
            membership[i] = membership_OCL[i];
        }
        for (j = 0; j < n_features; j++) {
            new_centers[cluster_id][j] += feature[i][j];
        }
    }

    free(feature_swap);
    free(cluster_linear);

    return delta;
}

int main(int argc, char** argv)
{
    printf("WG size of kernel_swap = %d, WG size of kernel_kmeans = %d \n", BLOCK_SIZE, BLOCK_SIZE2);

    setup(argc, argv);
    deallocateMemory();

    return 0;
}

