    peri_col = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));

    // Main iteration over diagonal blocks
    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {

