fp 
kernel_cam(	fp timeinst,
			fp *d_initvalu,
			int valu_offset,
			fp *d_params,
			int params_offset,
			fp *d_com,
			int com_offset,
			fp Ca){

	fp Btot;
	fp CaMKIItot;
	fp CaNtot;
	fp PP1tot;
	fp K;
	fp Mg;

	int offset_1;
	int offset_2;
	int offset_3;
