	fp k4Boff;
	fp k4Bon;

	fp k20B;
	fp k02B;
	fp k42B;
	fp k24B;

	fp kbi;
	fp kib;
	fp kpp1;
	fp Kmpp1;
	fp kib2;
	fp kb2i;
	fp kb24;
	fp kb42;
	fp kta;
	fp kat;
	fp kt42;
	fp kt24;
	fp kat2;
	fp kt2a;

	fp kcanCaoff;
	fp kcanCaon;
	fp kcanCaM4on;
	fp kcanCaM4off;
	fp kcanCaM2on;
	fp kcanCaM2off;
	fp kcanCaM0on;
	fp kcanCaM0off;
	fp k02can;
	fp k20can;
	fp k24can;
	fp k42can;

	fp rcn02;
	fp rcn24;

	fp B;
	fp rcn02B;
	fp rcn24B;
	fp rcn0B;
	fp rcn2B;
	fp rcn4B;

	fp Ca2CaN;
	fp rcnCa4CaN;
	fp rcn02CaN; 
	fp rcn24CaN;
	fp rcn0CaN;
	fp rcn2CaN;
	fp rcn4CaN;

	fp Pix;
	fp rcnCKib2;
	fp rcnCKb2b;
	fp rcnCKib;
	fp T;
	fp kbt;
	fp rcnCKbt;
	fp rcnCKtt2;
	fp rcnCKta;
	fp rcnCKt2a;
	fp rcnCKt2b2;
	fp rcnCKai;

	fp dCaM;
	fp dCa2CaM;
	fp dCa4CaM;
	fp dCaMB;
	fp dCa2CaMB;
	fp dCa4CaMB;

	fp dPb2;
	fp dPb;
	fp dPt;
	fp dPt2;
	fp dPa;

	fp dCa4CaN;
	fp dCaMCa4CaN;
	fp dCa2CaMCa4CaN;
	fp dCa4CaMCa4CaN;

	fp JCa;

	Btot = d_params[params_offset+1];
	CaMKIItot = d_params[params_offset+2];
	CaNtot = d_params[params_offset+3];
	PP1tot = d_params[params_offset+4];
	K = d_params[16];
	Mg = d_params[17];

	offset_1 = valu_offset;
	offset_2 = valu_offset+1;
	offset_3 = valu_offset+2;
	offset_4 = valu_offset+3;
	offset_5 = valu_offset+4;
	offset_6 = valu_offset+5;
