void 
master(	fp timeinst,
		fp *initvalu,
		fp *parameter,
		fp *finavalu,
		fp *com)
{

	int i;

	int initvalu_offset_ecc;
	int initvalu_offset_Dyad;
	int initvalu_offset_SL;
	int initvalu_offset_Cyt;

	fp JCaDyad;
	fp JCaSL;
	fp JCaCyt;

	kernel_gpu_opencl(	timeinst,
						initvalu,
						finavalu,
						parameter,
						com);

	JCaDyad = com[0];
	JCaSL = com[1];
	JCaCyt = com[2];

	initvalu_offset_ecc = 0;
	initvalu_offset_Dyad = 46;
	initvalu_offset_SL = 61;
	initvalu_offset_Cyt = 76;

	kernel_fin(	initvalu,
				initvalu_offset_ecc,
				initvalu_offset_Dyad,
				initvalu_offset_SL,
				initvalu_offset_Cyt,
				parameter,
				finavalu,
				JCaDyad,
				JCaSL,
				JCaCyt);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;
		}
		else if (isinf(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;
		}
	}

}

int 
solver(	fp **y,
		fp *x,
		int xmax,
		fp *params,
		fp *com)
{

	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	int i, j, k;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmax < xmin || h <= 0.0){
		return -2;
	}

	if (xmax == xmin){
		return 0; 
	}

	if (h > (xmax - xmin) ) { 
		h = (fp)xmax - (fp)xmin; 
	}

	printf("Time Steps: ");
	fflush(0);

	for(k=1; k<=xmax; k++) {

		x[k] = k-1;
		h = h_init;

		scale_fina = 1.0;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(	x[k],
									h,
									y[k-1],
									y[k],
									err,
									params,
									com);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR; 
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9) {
				h = 0.9;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}

			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}

		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			return -1; 
		}

		printf("%d ", k);
		fflush(0);

	}

	printf("\n");
	fflush(0);

	free(err);
	free(scale);
	free(yy);

	return 0;

}

int 
isInteger(char *str){

	if (*str == '\0'){
		return 0;
	}

	for(; *str != '\0'; str++){
		if (*str < 48 || *str > 57){	
			return 0;
		}
	}

	return 1;
}

void 
read_file(	char* filename,
			fp* input,
			int data_rows, 
			int data_cols,
			int major){

	FILE* fid;
	int i, j;
	fp temp;

	fid = fopen(filename, "r");
	if( fid == NULL ){
		printf( "The file was not opened for reading\n" );
		fflush(0);
		return;
	}

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%f", &temp);
				input[i*data_cols+j] = (fp)temp;
			}
		}
	}
	else{
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%f", &temp);
				input[j*data_rows+i] = (fp)temp;
			}
		}
	}

	fclose(fid);

}

long long 
get_time() {

	struct timeval tv;
	gettimeofday(&tv, NULL);

	return (tv.tv_sec * 1000000) + tv.tv_usec;
}

int device_id_inuse = 0;
int platform_id_inuse = 0;

int 
kernel_gpu_opencl_wrapper(	int xmax,
							int workload,

							fp ***y,
							fp **x,
							fp **params,
							fp *com)
{

	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;

	time0 = get_time();

	int i;

	time1 = get_time();

	time2 = get_time();

	int status;

	for(i=0; i<workload; i++){

		status = solver(	y[i],
							x[i],
							xmax,
							params[i],
							com);

		if(status !=0){
			printf("STATUS: %d\n", status);
		}

	}

	time3 = get_time();

	time4= get_time();

	printf("Time spent in different stages of the application:\n");
	printf("%15.12f s, %15.12f % : CPU: GPU SETUP\n", 							(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time4-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", 					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time4-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: COMPUTATION\n", 							(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time4-time0) * 100);

	printf("%15.12f s, %15.12f % : CPU: FREE GPU MEMORY\n", 						(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time4-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", 															(float) (time4-time0) / 1000000);

	return 0;

}

int 
main(	int argc, 
		char *argv []){

	int cur_arg;
	int xmax;
	int workload = 1;
    char *data_dir = "data";

	if(argc>3){
		for(cur_arg=1; cur_arg<argc; cur_arg++){

			if(strcmp(argv[cur_arg], "-time")==0){

				if(argc>=cur_arg+1){

					if(isInteger(argv[cur_arg+1])==1){
						xmax = atoi(argv[cur_arg+1]);
						if(xmax<0){
							printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
							return 0;
						}
						cur_arg = cur_arg+1;
					}

					else{
						printf("ERROR: Value to -time argument in not a number\n");
						return 0;
					}
				}

				else{
					printf("ERROR: Missing value to -time argument\n");
					return 0;
				}
			}
            else if(strcmp(argv[cur_arg], "-p")==0) {
				if(argc>=cur_arg+1)
					if(isInteger(argv[cur_arg+1])==1) {
						platform_id_inuse = atoi(argv[cur_arg+1]);
						cur_arg = cur_arg+1;
					}
