        initvalu_temp[i] = initvalu[i] + h * (b71 * finavalu_temp[0][i] + b74 * finavalu_temp[3][i] + b75 * finavalu_temp[4][i] + b76 * finavalu_temp[5][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[6], com);

    timeinst_temp = timeinst + a8 * h;
    for (i = 0; i < EQUATIONS; i++) {
        initvalu_temp[i] = initvalu[i] + h * (b81 * finavalu_temp[0][i] + b85 * finavalu_temp[4][i] + b86 * finavalu_temp[5][i] + b87 * finavalu_temp[6][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[7], com);

    timeinst_temp = timeinst + a9 * h;
    for (i = 0; i < EQUATIONS; i++) {
        initvalu_temp[i] = initvalu[i] + h * (b91 * finavalu_temp[0][i] + b94 * finavalu_temp[3][i] + b95 * finavalu_temp[4][i] + b96 * finavalu_temp[5][i] + b97 * finavalu_temp[6][i] + b98 * finavalu_temp[7][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[8], com);

    timeinst_temp = timeinst + a10 * h;
    for (i = 0; i < EQUATIONS; i++) {
        initvalu_temp[i] = initvalu[i] + h * (b10_1 * finavalu_temp[0][i] + b10_4 * finavalu_temp[3][i] + b10_5 * finavalu_temp[4][i] + b10_6 * finavalu_temp[5][i] + b10_7 * finavalu_temp[6][i] + b10_8 * finavalu_temp[7][i] + b10_9 * finavalu_temp[8][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[9], com);

    timeinst_temp = timeinst + h;
    for (i = 0; i < EQUATIONS; i++) {
        initvalu_temp[i] = initvalu[i] + h * (b11_1 * finavalu_temp[0][i] + b11_4 * finavalu_temp[3][i] + b11_5 * finavalu_temp[4][i] + b11_6 * finavalu_temp[5][i] + b11_7 * finavalu_temp[6][i] + b11_8 * finavalu_temp[7][i] + b11_9 * finavalu_temp[8][i] + b11_10 * finavalu_temp[9][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[10], com);

    timeinst_temp = timeinst;
    for (i = 0; i < EQUATIONS; i++) {
        initvalu_temp[i] = initvalu[i] + h * (b12_1 * finavalu_temp[0][i] + b12_6 * finavalu_temp[5][i] + b12_7 * finavalu_temp[6][i] + b12_8 * finavalu_temp[7][i] + b12_9 * finavalu_temp[8][i] + b12_10 * finavalu_temp[9][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[11], com);

    timeinst_temp = timeinst + h;
    for (i = 0; i < EQUATIONS; i++) {
        initvalu_temp[i] = initvalu[i] + h * (b13_1 * finavalu_temp[0][i] + b13_4 * finavalu_temp[3][i] + b13_5 * finavalu_temp[4][i] + b13_6 * finavalu_temp[5][i] + b13_7 * finavalu_temp[6][i] + b13_8 * finavalu_temp[7][i] + b13_9 * finavalu_temp[8][i] + b13_10 * finavalu_temp[9][i] + finavalu_temp[11][i]);
    }
    master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[12], com);

    for (i = 0; i < EQUATIONS; i++) {
        finavalu[i] = initvalu[i] + h * (c_1_11 * (finavalu_temp[0][i] + finavalu_temp[10][i]) + c6 * finavalu_temp[5][i] + c_7_8 * (finavalu_temp[6][i] + finavalu_temp[7][i]) + c_9_10 * (finavalu_temp[8][i] + finavalu_temp[9][i]));
    }

    for (i = 0; i < EQUATIONS; i++) {
        error[i] = fabs(err_factor * (finavalu_temp[0][i] + finavalu_temp[10][i] - finavalu_temp[11][i] - finavalu_temp[12][i]));
    }

    free(initvalu_temp);
    for (i = 0; i < 13; i++) {
        free(finavalu_temp[i]);
    }
    free(finavalu_temp);
}

int solver(fp **y, fp *x, int xmax, fp *params, fp *com) {
    fp err_exponent;
    int error;
    int outside;
    fp h;
    fp h_init;
    fp tolerance;
    int xmin;
    fp scale_min;
    fp scale_fina;
    fp *err = (fp *)malloc(EQUATIONS * sizeof(fp));
    fp *scale = (fp *)malloc(EQUATIONS * sizeof(fp));
    fp *yy = (fp *)malloc(EQUATIONS * sizeof(fp));
    int i, j, k;

    err_exponent = 1.0 / 7.0;
    h_init = 1;
    h = h_init;
    xmin = 0;
    tolerance = 10 / (fp)(xmax - xmin);
    x[0] = 0;

    if (xmax < xmin || h <= 0.0) {
        free(err);
        free(scale);
        free(yy);
        return -2;
    }

    if (xmax == xmin) {
        free(err);
        free(scale);
        free(yy);
        return 0;
    }

    if (h > (xmax - xmin)) {
        h = (fp)xmax - (fp)xmin;
    }

    printf("Time Steps: ");
    fflush(stdout);

    for (k = 1; k <= xmax; k++) {
        x[k] = k - 1;
        h = h_init;
        scale_fina = 1.0;

        for (j = 0; j < ATTEMPTS; j++) {
            error = 0;
            outside = 0;
            scale_min = MAX_SCALE_FACTOR;

            embedded_fehlberg_7_8(x[k], h, y[k - 1], y[k], err, params, com);

            for (i = 0; i < EQUATIONS; i++) {
                if (err[i] > 0) {
                    error = 1;
                }
            }
            if (error != 1) {
                scale_fina = MAX_SCALE_FACTOR;
                break;
            }

            for (i = 0; i < EQUATIONS; i++) {
                if (y[k - 1][i] == 0.0) {
                    yy[i] = tolerance;
                } else {
                    yy[i] = fabs(y[k - 1][i]);
                }
                scale[i] = 0.8 * pow(tolerance * yy[i] / err[i], err_exponent);
                if (scale[i] < scale_min) {
                    scale_min = scale[i];
                }
            }
            scale_fina = scale_min < MIN_SCALE_FACTOR ? MIN_SCALE_FACTOR : (scale_fina > MAX_SCALE_FACTOR ? MAX_SCALE_FACTOR : scale_min);

            for (i = 0; i < EQUATIONS; i++) {
                if (err[i] > (tolerance * yy[i])) {
                    outside = 1;
                }
            }
            if (outside == 0) {
                break;
            }

            h = h * scale_fina;
            if (h >= 0.9) {
                h = 0.9;
            }
            if (x[k] + h > (fp)xmax) {
                h = (fp)xmax - x[k];
            } else if (x[k] + h + 0.5 * h > (fp)xmax) {
                h = 0.5 * h;
            }
        }

        x[k] = x[k] + h;

        if (j >= ATTEMPTS) {
            free(err);
            free(scale);
            free(yy);
            return -1;
        }

        printf("%d ", k);
        fflush(stdout);
    }

    printf("\n");
    fflush(stdout);

    free(err);
    free(scale);
    free(yy);

    return 0;
}

int isInteger(char *str) {
    if (*str == '\0') {
        return 0;
    }
    for (; *str != '\0'; str++) {
        if (*str < 48 || *str > 57) {
            return 0;
        }
    }
    return 1;
}

void read_file(char *filename, fp *input, int data_rows, int data_cols, int major) {
    FILE *fid;
    int i, j;
    fp temp;

    fid = fopen(filename, "r");
    if (fid == NULL) {
        printf("The file was not opened for reading\n");
        fflush(stdout);
        return;
    }

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%f", &temp);
                input[i * data_cols + j] = (fp)temp;
            }
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%f", &temp);
                input[j * data_rows + i] = (fp)temp;
            }
        }
    }

    fclose(fid);
}

int kernel_gpu_opencl_wrapper(int xmax, int workload, fp ***y, fp **x, fp **params, fp *com) {
    int i, j, status;

    #pragma omp parallel
    {
        #pragma omp single
        {
            printf("OpenMP running with %d threads\n", omp_get_num_threads());
        }
    }

    for (i = 0; i < workload; i++) {
        status = solver(y[i], x[i], xmax, params[i], com);
        if (status != 0) {
            printf("STATUS: %d\n", status);
        }
    }

    FILE *pFile;
    pFile = fopen("output.txt", "w");
    if (pFile == NULL) {
        fputs("fopen example", pFile);
        return -1;
    }

    int k;
    for (i = 0; i < workload; i++) {
        fprintf(pFile, "WORKLOAD %d:\n", i);
        for (j = 0; j < (xmax + 1); j++) {
            fprintf(pFile, "\tTIME %d:\n", j);
            for (k = 0; k < EQUATIONS; k++) {
                fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
            }
        }
    }

    fclose(pFile);

    for (i = 0; i < workload; i++) {
        for (j = 0; j < (1 + xmax); j++) {
            free(y[i][j]);
        }
        free(y[i]);
    }
    free(y);

    for (i = 0; i < workload; i++) {
        free(x[i]);
    }
    free(x);

    for (i = 0; i < workload; i++) {
        free(params[i]);
    }
    free(params);

    free(com);

    return 0;
}

int main(int argc, char *argv[]) {
    int cur_arg;
    int xmax = 100;
    int workload = 1;
    char *data_dir = ".";

    if (argc > 3) {
        for (cur_arg = 1; cur_arg < argc; cur_arg++) {
            if (strcmp(argv[cur_arg], "-time") == 0) {
                if (argc >= cur_arg + 1) {
                    if (isInteger(argv[cur_arg + 1]) == 1) {
                        xmax = atoi(argv[cur_arg + 1]);
                        if (xmax < 0) {
                            printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
                            return 0;
                        }
                        cur_arg = cur_arg + 1;
                    } else {
                        printf("ERROR: Value to -time argument is not a number\n");
                        return 0;
                    }
                } else {
                    printf("ERROR: Missing value to -time argument\n");
                    return 0;
                }
            } else if (strcmp(argv[cur_arg], "-r") == 0) {
                if (argc >= cur_arg + 1) {
                    data_dir = argv[cur_arg + 1];
                    cur_arg++;
                }
            } else {
                printf("ERROR: Unknown argument\n");
                return 0;
            }
        }
    } else {
        printf("Provide time argument, example: -time 100\n");
        return 0;
    }

    if (workload == 1) {
        int i, j;
        long long memory;
        memory = workload * (xmax + 1) * EQUATIONS * 4;
        if (memory > 1000000000) {
            printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
            return 0;
        }

        fp ***y;
        y = (fp ***)malloc(workload * sizeof(fp **));
        for (i = 0; i < workload; i++) {
            y[i] = (fp **)malloc((1 + xmax) * sizeof(fp *));
            for (j = 0; j < (1 + xmax); j++) {
                y[i][j] = (fp *)malloc(EQUATIONS * sizeof(fp));
            }
        }

        fp **x;
        x = (fp **)malloc(workload * sizeof(fp *));
        for (i = 0; i < workload; i++) {
            x[i] = (fp *)malloc((1 + xmax) * sizeof(fp));
        }

        fp **params;
        params = (fp **)malloc(workload * sizeof(fp *));
        for (i = 0; i < workload; i++) {
            params[i] = (fp *)malloc(PARAMETERS * sizeof(fp));
        }

        fp *com;
        com = (fp *)malloc(3 * sizeof(fp));

        char y_file[100];
        sprintf(y_file, "%s/%s", data_dir, "y.txt");
        for (i = 0; i < workload; i++) {
            read_file(y_file, y[i][0], EQUATIONS, 1, 0);
        }

        char params_file[100];
        sprintf(params_file, "%s/%s", data_dir, "params.txt");
        for (i = 0; i < workload; i++) {
            read_file(params_file, params[i], PARAMETERS, 1, 0);
        }

        kernel_gpu_opencl_wrapper(xmax, workload, y, x, params, com);
    }

    return 0;
}

