#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <omp.h>
#include <vector>
#include <iostream>

using namespace std;

#define REC_LENGTH 49

typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[REC_LENGTH];
    float distance;
} Record;

char *data_folder = NULL;

#ifdef _WIN32
#include <windows.h>
#define DELTA_EPOCH_IN_MICROSECS  11644473600000000ULL

int gettimeofday(struct timeval *tv, struct timezone *tz) {
    FILETIME ft;
    unsigned __int64 tmpres = 0;

    if (NULL != tv) {
        GetSystemTimeAsFileTime(&ft);
        tmpres |= ft.dwHighDateTime;
        tmpres <<= 32;
        tmpres |= ft.dwLowDateTime;
        tmpres /= 10;
        tmpres -= DELTA_EPOCH_IN_MICROSECS;
        tv->tv_sec = (long)(tmpres / 1000000UL);
        tv->tv_usec = (long)(tmpres % 1000000UL);
    }
    return 0;
}
#else
#include <sys/time.h>
#endif

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

void tvsub(struct timeval *tminus, struct timeval *tfrom, struct timeval *tresult) {
    tresult->tv_sec = tfrom->tv_sec - tminus->tv_sec;
    tresult->tv_usec = tfrom->tv_usec - tminus->tv_usec;
    if (tresult->tv_usec < 0) {
        tresult->tv_sec--;
        tresult->tv_usec += 1000000;
    }
}

void* alloc(size_t size) {
    void* ptr = malloc(size);
    if(ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(0);
    }

    while(!feof(flist)) {
        if(fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if(!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while(!feof(fp)){
            Record record;
            LatLong latLong;
            fgets(record.recString, 49, fp);
            fgetc(fp);
            if (feof(fp)) break;

            char substr[6];
            for(i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record *tempRec;
    float tempDist;

    for(i = 0; i < topN; i++) {
        minLoc = i;
        for(j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = &records[i];
        records[i] = records[minLoc];
        records[minLoc] = *tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for(i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        *lat = atof(argv[i+1]);
                    } else {
                        *lng = atof(argv[i+1]);
                    }
                    i++;
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
                case 'f':
                    i++;
                    data_folder = argv[i];
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

