float *OpenMPFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    LatLong *locations_array = (LatLong *)malloc(sizeof(LatLong) * numRecords);
    float *distances = (float *)malloc(sizeof(float) * numRecords);

    for (int i = 0; i < numRecords; i++) {
        locations_array[i] = locations[i];
    }

    double start_time = 0.0, end_time = 0.0;
    if (timing) {
        start_time = omp_get_wtime();
    }

    computeNearestNeighbor(locations_array, distances, numRecords, lat, lng);

    if (timing) {
        end_time = omp_get_wtime();
        printf("# Records\tKernel(s)\t\tTotal(s)\n");
        printf("%d        \t%f\t%f\n\n", numRecords, end_time - start_time, end_time - start_time);
    }

    free(locations_array);

    return distances;
}

