    for (int globalId = 0; globalId < numRecords; globalId++) {
        LatLong *latLong = &locations[globalId];
        distances[globalId] = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) +
                                          (lng - latLong->lng) * (lng - latLong->lng));
