void read_graphics(char* filename, fp* input, int data_rows, int data_cols, int major) {
    FILE* fid;
    int i, j;
    char c;
    int temp;

    fid = fopen(filename, "r");
    if( fid == NULL ){
        printf( "The file was not opened for reading\n" );
        return;
    }

    i = 0;
    while(i<3){
        c = fgetc(fid);
        if(c == '\n'){
            i = i+1;
        }
    };

    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%d", &temp);
                input[i*data_cols+j] = (fp)temp;
